/* ================================================================
   Gallery Page — Gallery.css
   ================================================================ */

/* ── Page ── */
.gallery-page {
  background: #050505;
  cursor: none;
  /* hide default — custom cursor active */
}

/* ── Custom cursor (image preview bubble) ── */
.gl-cursor {
  position: fixed;
  top: 0;
  left: 0;
  width: 130px;
  height: 90px;
  border-radius: 14px;
  overflow: hidden;
  pointer-events: none;
  z-index: 8888;
  border: 2px solid rgba(212, 175, 55, 0.6);
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.55);
  will-change: transform;
  transform-origin: center center;
}

.gl-cursor-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* Restore cursor inside lightbox */
.gl-lightbox-backdrop {
  cursor: auto;
}

/* ================================================================
   GALLERY SECTION
   ================================================================ */
.gallery-section {
  position: relative;
  padding: 100px 0 140px;
  overflow: hidden;
  /* opacity: 1 — was 0 only because the fold timeline animated it in */
}

/* ── Background collage wall ── */
.gallery-collage {
  position: absolute;
  inset: 0;
  z-index: 0;
  overflow: hidden;
  pointer-events: none;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  gap: 20px;
  padding: 20px 0;
}

.collage-row {
  display: flex;
  gap: 28px;
  width: max-content;
}

.collage-row img {
  width: 260px;
  height: 175px;
  object-fit: cover;
  border-radius: 14px;
  opacity: 0.1;
  filter: grayscale(15%);
}

.scroll-left {
  animation: scrollLeft 140s linear infinite;
}

.scroll-right {
  animation: scrollRight 160s linear infinite;
}

@keyframes scrollLeft {
  0% {
    transform: translateX(0);
  }

  100% {
    transform: translateX(-50%);
  }
}

@keyframes scrollRight {
  0% {
    transform: translateX(-50%);
  }

  100% {
    transform: translateX(0);
  }
}

.gallery-collage::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(to bottom,
      rgba(5, 5, 5, 0.7) 0%,
      rgba(5, 5, 5, 0.55) 50%,
      rgba(5, 5, 5, 0.7) 100%);
}

/* ── Ambient orbs ── */
.gl-orb {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
  filter: blur(110px);
  opacity: 0.1;
  z-index: 0;
}

.gl-orb-a {
  width: 600px;
  height: 600px;
  background: radial-gradient(circle, #d4af37, transparent 65%);
  top: -160px;
  right: -180px;
  animation: orb-a 9s ease-in-out infinite alternate;
}

.gl-orb-b {
  width: 440px;
  height: 440px;
  background: radial-gradient(circle, #d4af37, transparent 65%);
  bottom: 60px;
  left: -120px;
  animation: orb-b 12s ease-in-out infinite alternate;
}

@keyframes orb-a {
  from {
    transform: translate(0, 0) scale(1);
  }

  to {
    transform: translate(-40px, 30px) scale(1.1);
  }
}

@keyframes orb-b {
  from {
    transform: translate(0, 0) scale(1);
  }

  to {
    transform: translate(30px, -30px) scale(1.08);
  }
}

/* ── Inner container ── */
.gl-inner {
  position: relative;
  z-index: 2;
  max-width: 1280px;
  margin: 0 auto;
  padding: 0 32px;
}

/* ================================================================
   GALLERY HEADER
   ================================================================ */
.gl-header {
  text-align: center;
  margin-bottom: 72px;
}

.gl-eyebrow-row {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 16px;
  margin-bottom: 18px;
}

.gl-eyebrow {
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 3px;
  text-transform: uppercase;
  color: rgba(212, 175, 55, 0.85);
}

.gl-count-tag {
  display: inline-flex;
  align-items: center;
  padding: 4px 14px;
  background: #d4af37;
  color: #000;
  font-size: 11px;
  font-weight: 800;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  border-radius: 30px;
  animation: badge-glow 3s ease-in-out infinite;
}

@keyframes badge-glow {

  0%,
  100% {
    box-shadow: 0 0 14px rgba(212, 175, 55, 0.35);
  }

  50% {
    box-shadow: 0 0 30px rgba(212, 175, 55, 0.65);
  }
}

.gl-title {
  font-size: clamp(40px, 6vw, 72px);
  font-weight: 800;
  color: #fff;
  letter-spacing: -1px;
  line-height: 1.1;
  margin: 0 0 28px;
}

.gl-title-word {
  display: inline-block;
}

.gl-title-gold {
  background: linear-gradient(135deg, #d4af37 20%, #f5d06e 60%, #d4af37 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  position: relative;
}

/* Shimmer underline on gold word */
.gl-title-gold::after {
  content: '';
  position: absolute;
  bottom: -8px;
  left: 0;
  width: 100%;
  height: 3px;
  background: linear-gradient(90deg, #d4af37, #f5d06e, #d4af37);
  background-size: 200%;
  border-radius: 2px;
  transform: scaleX(0);
  transform-origin: left;
  animation: underline-in 0.9s 1.1s ease forwards,
    shimmer-slide 2.5s 2s ease-in-out infinite;
}

@keyframes underline-in {
  to {
    transform: scaleX(1);
  }
}

@keyframes shimmer-slide {
  0% {
    background-position: 200% center;
  }

  100% {
    background-position: -200% center;
  }
}

/* Divider */
.gl-divider {
  width: 72px;
  height: 3px;
  background: linear-gradient(90deg, #d4af37, #f5d06e);
  border-radius: 2px;
  margin: 0 auto;
  transform-origin: center;
}

/* ================================================================
   GALLERY GRID
   ================================================================ */
.gl-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 20px;
  grid-auto-rows: 260px;
}

/* Span pattern for visual rhythm */
.gl-item:nth-child(1)  { grid-row: span 2; }
.gl-item:nth-child(7)  { grid-row: span 2; }
.gl-item:nth-child(13) { grid-row: span 2; }
.gl-item:nth-child(19) { grid-row: span 2; }
.gl-item:nth-child(25) { grid-row: span 2; }
.gl-item:nth-child(31) { grid-row: span 2; }
.gl-item:nth-child(37) { grid-row: span 2; }
.gl-item:nth-child(43) { grid-row: span 2; }

/* ── Gallery Item ── */
.gl-item {
  position: relative;
  overflow: hidden;
  border-radius: 16px;
  cursor: pointer;
  transform-style: preserve-3d;
  will-change: transform;
  border: 1px solid rgba(255, 255, 255, 0.06);
  transition: border-color 0.4s ease, box-shadow 0.4s ease;
  background: #111;
}

.gl-item:hover {
  border-color: rgba(212, 175, 55, 0.5);
  box-shadow:
    0 20px 60px rgba(0, 0, 0, 0.5),
    0 0 0 1px rgba(212, 175, 55, 0.3),
    0 0 40px rgba(212, 175, 55, 0.08);
  z-index: 2;
}

.gl-item img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  transition: transform 0.7s ease, filter 0.5s ease;
  filter: brightness(0.85) saturate(0.9);
}

.gl-item:hover img {
  transform: scale(1.1);
  filter: brightness(1) saturate(1.1);
}

/* ── Dark gradient overlay ── */
.gl-item-overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(to top,
      rgba(0, 0, 0, 0.7) 0%,
      rgba(0, 0, 0, 0.1) 55%,
      transparent 100%);
  opacity: 0;
  transition: opacity 0.45s ease;
  z-index: 1;
}

.gl-item:hover .gl-item-overlay {
  opacity: 1;
}

/* ── Diagonal shine sweep ── */
.gl-item-shine {
  position: absolute;
  inset: 0;
  background: linear-gradient(115deg,
      transparent 25%,
      rgba(255, 255, 255, 0.13) 50%,
      transparent 75%);
  background-size: 200% 200%;
  background-position: -100% 0;
  pointer-events: none;
  z-index: 3;
}

.gl-item:hover .gl-item-shine {
  animation: gl-shine 0.65s ease forwards;
}

@keyframes gl-shine {
  from {
    background-position: -100% 0;
  }

  to {
    background-position: 200% 0;
  }
}

/* ── Expand icon ── */
.gl-item-zoom {
  position: absolute;
  top: 14px;
  right: 14px;
  width: 38px;
  height: 38px;
  background: rgba(0, 0, 0, 0.6);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  opacity: 0;
  transform: scale(0.6) rotate(-20deg);
  transition: opacity 0.35s ease, transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
  z-index: 4;
  backdrop-filter: blur(6px);
  -webkit-backdrop-filter: blur(6px);
}

.gl-item:hover .gl-item-zoom {
  opacity: 1;
  transform: scale(1) rotate(0deg);
}

/* ── Index number (bottom-left on hover) ── */
.gl-item-index {
  position: absolute;
  bottom: 14px;
  left: 16px;
  font-size: 11px;
  font-weight: 800;
  letter-spacing: 1.5px;
  color: rgba(212, 175, 55, 0.9);
  opacity: 0;
  transform: translateY(8px);
  transition: opacity 0.35s ease, transform 0.35s ease;
  z-index: 4;
}

.gl-item:hover .gl-item-index {
  opacity: 1;
  transform: translateY(0);
}

/* ================================================================
   LIGHTBOX
   ================================================================ */
.gl-lightbox-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.93);
  z-index: 9999;
  display: flex;
  align-items: center;
  justify-content: center;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  animation: lb-in 0.3s ease;
}

@keyframes lb-in {
  from {
    opacity: 0;
  }

  to {
    opacity: 1;
  }
}

.gl-lightbox-inner {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 100%;
  padding-bottom: 100px;
}

.gl-lb-img {
  max-width: 82vw;
  max-height: 78vh;
  object-fit: contain;
  border-radius: 14px;
  box-shadow: 0 32px 100px rgba(0, 0, 0, 0.8), 0 0 0 1px rgba(212, 175, 55, 0.15);
  display: block;
}

/* Close */
.gl-lb-close {
  position: fixed;
  top: 22px;
  right: 26px;
  width: 44px;
  height: 44px;
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid rgba(255, 255, 255, 0.18);
  border-radius: 50%;
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: background 0.25s, transform 0.3s ease;
  z-index: 10;
}

.gl-lb-close:hover {
  background: rgba(255, 255, 255, 0.18);
  transform: rotate(90deg) scale(1.1);
}

/* Prev / Next */
.gl-lb-nav {
  position: fixed;
  top: 50%;
  transform: translateY(-50%);
  width: 54px;
  height: 54px;
  background: rgba(255, 255, 255, 0.07);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 50%;
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: background 0.25s, transform 0.25s;
  z-index: 10;
}

.gl-lb-nav:hover {
  background: #d4af37;
  color: #000;
}

.gl-lb-prev {
  left: 22px;
}

.gl-lb-next {
  right: 22px;
}

.gl-lb-prev:hover {
  transform: translateY(-50%) translateX(-4px);
}

.gl-lb-next:hover {
  transform: translateY(-50%) translateX(4px);
}

/* Thumbnail strip */
.gl-lb-strip {
  position: fixed;
  bottom: 20px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  gap: 8px;
  padding: 10px 14px;
  background: rgba(0, 0, 0, 0.55);
  border-radius: 30px;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.08);
  max-width: 90vw;
  overflow-x: auto;
  scrollbar-width: none;
  z-index: 10;
}

.gl-lb-strip::-webkit-scrollbar {
  display: none;
}

.gl-lb-thumb {
  width: 48px;
  height: 34px;
  border-radius: 7px;
  background-size: cover;
  background-position: center;
  border: 2px solid transparent;
  opacity: 0.45;
  flex-shrink: 0;
  cursor: pointer;
  transition: opacity 0.25s, border-color 0.25s, transform 0.25s;
}

.gl-lb-thumb:hover {
  opacity: 0.8;
  transform: translateY(-2px);
}

.gl-lb-thumb.active {
  border-color: #d4af37;
  opacity: 1;
  transform: translateY(-3px) scale(1.05);
  box-shadow: 0 4px 14px rgba(212, 175, 55, 0.4);
}

/* Counter */
.gl-lb-counter {
  position: fixed;
  top: 28px;
  left: 50%;
  transform: translateX(-50%);
  font-size: 12px;
  color: rgba(255, 255, 255, 0.45);
  font-weight: 600;
  letter-spacing: 1.5px;
  background: rgba(0, 0, 0, 0.4);
  padding: 5px 18px;
  border-radius: 30px;
  backdrop-filter: blur(6px);
  -webkit-backdrop-filter: blur(6px);
  z-index: 10;
}

/* ================================================================
   RESPONSIVE
   ================================================================ */
@media (max-width: 1024px) {
  .gl-grid {
    grid-template-columns: repeat(2, 1fr);
    grid-auto-rows: 240px;
  }

  .gl-cursor {
    display: none;
  }

  .gallery-page {
    cursor: auto;
  }
}

@media (max-width: 640px) {
  .gallery-section {
    padding: 80px 0 120px;
  }

  .gl-inner {
    padding: 0 18px;
  }

  .gl-grid {
    grid-template-columns: 1fr;
    grid-auto-rows: 220px;
  }

  .gl-item:nth-child(n) {
    grid-row: span 1;
  }

  .gl-lb-nav {
    display: none;
  }

  .gl-lb-strip {
    gap: 6px;
    padding: 8px 10px;
  }

  .gl-lb-thumb {
    width: 38px;
    height: 28px;
  }
}
